<script lang="ts">
	import PortalHeader from '$lib/components/PortalHeader.svelte'; import StatusBadge from '$lib/components/StatusBadge.svelte'; import { CalendarDays, ArrowUpRight, FolderOpen, FileUp, MessageSquare, Check, ChevronLeft } from 'lucide-svelte';
	let {data}=$props(); let selected=$state<(typeof data.tasks)[number]|null>(null); let status=$state(''); let progress=$state(0); let notes=$state(''); let saved=$state(false);
	function openTask(task:(typeof data.tasks)[number]){selected=task;status=task.status;progress=task.progress;notes=''}
	async function update(){if(!selected)return; await fetch('/api/tasks/'+selected.id,{method:'PATCH',headers:{'content-type':'application/json'},body:JSON.stringify({status,progress,notes,token:data.editor.token})});saved=true;setTimeout(()=>saved=false,2500)}
</script>
<svelte:head><title>{data.editor.name}’s work — StudioFlow</title></svelte:head><PortalHeader label="Editor portal"/>
<main class="portal-main">{#if !selected}<div class="welcome"><span class="avatar">{data.editor.initials}</span><div><p>Welcome back</p><h1>{data.editor.name}</h1></div></div><div class="work-title"><h2>Today’s tasks</h2><span>{data.tasks.length} assigned</span></div><div class="task-cards">{#each data.tasks as task}<button class="task-card" onclick={()=>openTask(task)}><div class="task-card-top"><div><span class="customer">{task.customer}</span><h3>{task.project}</h3></div><StatusBadge status={task.status}/></div><p>{task.name}</p><div class="task-footer"><span><CalendarDays size={13}/> Due {task.due}</span><span class="open">Open <ArrowUpRight size={13}/></span></div></button>{/each}</div>{:else}<button class="back" onclick={()=>selected=null}><ChevronLeft size={15}/> All tasks</button><header class="task-heading"><div><span>{selected.customer}</span><h1>{selected.project}</h1><p>{selected.name}</p></div><StatusBadge status={status}/></header><div class="task-layout"><section class="card details"><h2>Work details</h2><dl><div><dt>Task</dt><dd>{selected.name}</dd></div><div><dt>Due date</dt><dd>{selected.due}</dd></div><div><dt>Files</dt><dd>{selected.fileCount||'Project folder'}</dd></div></dl><div class="instructions"><span>Instructions</span><p>{selected.instructions||'Follow the project brief and notify the admin if files are missing.'}</p></div><a class="folder" href={'https://'+selected.fileLink}><FolderOpen size={15}/> Open source files <ArrowUpRight size={13}/></a></section><section class="card update"><h2>Update your work</h2><div class="field"><label>Status</label><select bind:value={status}><option>Not started</option><option>Files downloaded</option><option>In progress</option><option>Waiting for clarification</option><option>Ready for review</option><option>Revision required</option><option>Completed</option></select></div><div class="field"><label>Progress <b>{progress}%</b></label><input class="range" type="range" min="0" max="100" step="10" bind:value={progress}/></div><div class="field"><label>Output link</label><div class="with-icon"><FileUp size={14}/><input placeholder="Paste Drive or upload link"/></div></div><div class="field"><label>Notes for admin</label><textarea bind:value={notes} placeholder="Add an update, question or missing-file report..."></textarea></div><button class="primary save" onclick={update}>Update task</button>{#if saved}<div class="saved"><Check size={13}/> Update sent to admin and Sheets</div>{/if}</section></div>{/if}</main>
